-- ============================================================
-- Lohikeitto: combined schema + seed migration
-- ============================================================

CREATE EXTENSION IF NOT EXISTS pg_trgm;

CREATE TABLE categories (
    slug  TEXT PRIMARY KEY,
    title TEXT NOT NULL
);

CREATE TABLE services (
    id                UUID PRIMARY KEY DEFAULT gen_random_uuid(),
    name              TEXT NOT NULL,
    slug              TEXT NOT NULL UNIQUE,
    bundle_id         TEXT UNIQUE,
    description       TEXT,
    domains           TEXT[] NOT NULL DEFAULT '{}',
    alternative_names TEXT[] NOT NULL DEFAULT '{}',
    tags              TEXT[] NOT NULL DEFAULT '{}',
    verified          BOOLEAN NOT NULL DEFAULT false,
    category_slug     TEXT REFERENCES categories(slug),
    colors            JSONB NOT NULL,
    social_links      JSONB NOT NULL DEFAULT '{}',
    ref_link          TEXT,
    created_at        TIMESTAMPTZ NOT NULL DEFAULT now()
);

-- ============================================================
-- Default categories
-- ============================================================


-- ============================================================
-- Services
-- ============================================================



CREATE TABLE limbus (
    id              UUID PRIMARY KEY DEFAULT gen_random_uuid(),
    name            TEXT NOT NULL,
    domain          TEXT NOT NULL UNIQUE,
    logo_url        TEXT,
    source          TEXT NOT NULL,
    created_at      TIMESTAMPTZ NOT NULL DEFAULT now()
);

-- ============================================================
-- Indexes
-- ============================================================

CREATE INDEX idx_services_name_trgm ON services USING gin (name gin_trgm_ops);
CREATE INDEX idx_services_domains ON services USING gin (domains);
CREATE INDEX idx_services_bundle ON services(bundle_id);
CREATE INDEX idx_services_alt_names ON services USING gin (alternative_names);
CREATE INDEX idx_services_tags ON services USING gin (tags);
